        idealFor: [['Firmy bogate w dane', 'Posiadają duże zbiory danych i potrzebują AI do ekstrakcji wzorców, wniosków i automatyzacji decyzji.'], ['Firmy produktowe', 'Chcą inteligentnych funkcji — rekomendacji, prognoz lub NLP — wbudowanych w swój produkt.'], ['Zespoły operacyjne', 'Chcą zautomatyzować kontrolę jakości, przetwarzanie dokumentów lub wykrywanie anomalii.']],
